import{_ as a,c as e,o as r,a4 as t}from"./chunks/framework.nQaBHiNx.js";const b=JSON.parse('{"title":"第二章 信息结构","description":"","frontmatter":{"permalink":"/note/the-art-of-computer-programming/02.html"},"headers":[],"relativePath":"computer/book/the-art-of-computer-programming/02-第二章 信息结构.md","filePath":"computer/book/the-art-of-computer-programming/02-第二章 信息结构.md"}'),o={name:"computer/book/the-art-of-computer-programming/02-第二章 信息结构.md"},h=t('<h1 id="第二章-信息结构" tabindex="-1">第二章 信息结构 <a class="header-anchor" href="#第二章-信息结构" aria-label="Permalink to &quot;第二章 信息结构&quot;">​</a></h1><h2 id="_2-1-引论" tabindex="-1">2.1 引论 <a class="header-anchor" href="#_2-1-引论" aria-label="Permalink to &quot;2.1 引论&quot;">​</a></h2><p>计算机程序通常都是对一些信息表进行操作。在大多数情况下，这些表并不仅仅是杂乱无章的数值集团；他们含有数据元素之间重要的结构关系。</p><p>在最简单的形式下，一个表可以是元素的一个线性表。这是它的有关结构的性质可以包括对诸如下列这样一些问题的答案：</p><ul><li>哪个元素是表中的头一个元素？</li><li>哪个元素是最后的元素？</li><li>那些元素居于给定的一个元素之前和之后？</li><li>在这种表中有多少个元素？</li></ul><p>在更复杂的情况下，表可以是一个二维的数组，或者是具有更高 n 值的 n 维数组；它可以是一个树结构，表示层次或分支关系；或者是复杂的具有大量交互联系的多重链接结构，如同在人的大脑中我们可以找到的那样。</p><p>为了合理地使用计算机，我们需要理解存在于数据内的结构关系，以及在一台计算机内表示和操作这样的结构的基本技术。</p><h2 id="_2-2-线性表" tabindex="-1">2.2 线性表 <a class="header-anchor" href="#_2-2-线性表" aria-label="Permalink to &quot;2.2 线性表&quot;">​</a></h2><h3 id="_2-2-1-栈、队列和双端队列" tabindex="-1">2.2.1 栈、队列和双端队列 <a class="header-anchor" href="#_2-2-1-栈、队列和双端队列" aria-label="Permalink to &quot;2.2.1 栈、队列和双端队列&quot;">​</a></h3><h3 id="_2-2-2-顺序分配" tabindex="-1">2.2.2 顺序分配 <a class="header-anchor" href="#_2-2-2-顺序分配" aria-label="Permalink to &quot;2.2.2 顺序分配&quot;">​</a></h3><h3 id="_2-2-3-链接分配" tabindex="-1">2.2.3 链接分配 <a class="header-anchor" href="#_2-2-3-链接分配" aria-label="Permalink to &quot;2.2.3 链接分配&quot;">​</a></h3><h3 id="_2-2-4-循环表" tabindex="-1">2.2.4 循环表 <a class="header-anchor" href="#_2-2-4-循环表" aria-label="Permalink to &quot;2.2.4 循环表&quot;">​</a></h3><h3 id="_2-2-5-双重链接表" tabindex="-1">2.2.5 双重链接表 <a class="header-anchor" href="#_2-2-5-双重链接表" aria-label="Permalink to &quot;2.2.5 双重链接表&quot;">​</a></h3><h3 id="_2-2-6-数组和正交表" tabindex="-1">2.2.6 数组和正交表 <a class="header-anchor" href="#_2-2-6-数组和正交表" aria-label="Permalink to &quot;2.2.6 数组和正交表&quot;">​</a></h3><h2 id="_2-3-树" tabindex="-1">2.3 树 <a class="header-anchor" href="#_2-3-树" aria-label="Permalink to &quot;2.3 树&quot;">​</a></h2><h3 id="_2-3-1-遍历二叉树" tabindex="-1">2.3.1 遍历二叉树 <a class="header-anchor" href="#_2-3-1-遍历二叉树" aria-label="Permalink to &quot;2.3.1 遍历二叉树&quot;">​</a></h3><h3 id="_2-3-2-树的二叉树表示" tabindex="-1">2.3.2 树的二叉树表示 <a class="header-anchor" href="#_2-3-2-树的二叉树表示" aria-label="Permalink to &quot;2.3.2 树的二叉树表示&quot;">​</a></h3><h3 id="_2-3-3-树的其他表示" tabindex="-1">2.3.3 树的其他表示 <a class="header-anchor" href="#_2-3-3-树的其他表示" aria-label="Permalink to &quot;2.3.3 树的其他表示&quot;">​</a></h3><h3 id="_2-3-4-树的基本数学性质" tabindex="-1">2.3.4 树的基本数学性质 <a class="header-anchor" href="#_2-3-4-树的基本数学性质" aria-label="Permalink to &quot;2.3.4 树的基本数学性质&quot;">​</a></h3><h3 id="_2-3-5-列表和废料收集" tabindex="-1">2.3.5 列表和废料收集 <a class="header-anchor" href="#_2-3-5-列表和废料收集" aria-label="Permalink to &quot;2.3.5 列表和废料收集&quot;">​</a></h3><h2 id="_2-4-多重链接结构" tabindex="-1">2.4 多重链接结构 <a class="header-anchor" href="#_2-4-多重链接结构" aria-label="Permalink to &quot;2.4 多重链接结构&quot;">​</a></h2><h2 id="_2-5-动态存储分配" tabindex="-1">2.5 动态存储分配 <a class="header-anchor" href="#_2-5-动态存储分配" aria-label="Permalink to &quot;2.5 动态存储分配&quot;">​</a></h2><h2 id="_2-6-历史和文献" tabindex="-1">2.6 历史和文献 <a class="header-anchor" href="#_2-6-历史和文献" aria-label="Permalink to &quot;2.6 历史和文献&quot;">​</a></h2>',23),i=[h];function l(n,_,d,c,s,u){return r(),e("div",null,i)}const q=a(o,[["render",l]]);export{b as __pageData,q as default};
